#include <bits/stdc++.h>using namespace std; void solve() {    int n, k;    cin >> n >> k;    vector<int> c(n);    for (int i = 0; i < n; i++)         cin >> c[i];    vector<int> gap1(k + 1, 0);    vector<int> gap2(k + 1, 0);    vector<int> last(k + 1, 0);    auto upd = [&](int col, int pos) {        int gap = pos - last[col] - 1;        if (gap > gap1[col]) {            gap2[col] = gap1[col];            gap1[col] = gap;        } else if (gap > gap2[col])            gap2[col] = gap;        last[col] = pos;    };    for (int i = 0; i < n; i++)        upd(c[i], i + 1);    for (int col = 1; col <= k; col++)         upd(col, n + 1);    int ans = 1e9;     for (int col = 1; col <= k; col++) {        int step = max(gap1[col] / 2, gap2[col]);        ans = min(ans, step);    }    cout << ans << "\n";} int main() {    ios_base::sync_with_stdio(false);    cin.tie(NULL);    int t;    cin >> t;    while (t--)        solve();    return 0;}